CREATE TABLE assets (id VARCHAR(36) NOT NULL, object_key VARCHAR(255) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, filename VARCHAR(255) NOT NULL, mime_type VARCHAR(255) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, size BIGINT UNSIGNED NOT NULL, sha256 CHAR(64) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, etag VARCHAR(255) NULL, status ENUM('quarantined','available','archived') NOT NULL, created_by VARCHAR(64) NOT NULL, created_at DATETIME(6) NOT NULL, confirmed_at DATETIME(6) NULL, archived_at DATETIME(6) NULL, upload_expires_at DATETIME(6) NOT NULL, PRIMARY KEY (id), UNIQUE KEY uq_assets_object_key (object_key), KEY idx_assets_list (created_at DESC,id DESC), KEY idx_assets_status_list (status,created_at DESC,id DESC), KEY idx_assets_mime_list (mime_type,created_at DESC,id DESC), KEY idx_assets_quarantine_cleanup (status,upload_expires_at), CONSTRAINT fk_assets_creator FOREIGN KEY (created_by) REFERENCES users (id), CONSTRAINT chk_assets_size CHECK (size BETWEEN 1 AND 5368709120), CONSTRAINT chk_assets_sha256 CHECK (sha256 REGEXP _ascii'^[a-f0-9]{64}$'), CONSTRAINT chk_assets_object_key CHECK (object_key REGEXP _ascii'^assets/ast_[a-f0-9]{32}/[a-f0-9]{32}$'), CONSTRAINT chk_assets_times CHECK ((status='quarantined' AND etag IS NULL AND confirmed_at IS NULL AND archived_at IS NULL) OR (status='available' AND etag IS NOT NULL AND confirmed_at IS NOT NULL AND archived_at IS NULL) OR (status='archived' AND etag IS NOT NULL AND confirmed_at IS NOT NULL AND archived_at IS NOT NULL))) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
